#include <stdio.h>
#include <stdlib.h>

/* Structure to represent a process */
typedef struct {
 int pid; // Process ID
 int arrival_time; // Time when process arrives in ready queue
 int burst_time; // CPU burst time (execution time)
 int completion_time;
 int turnaround_time;
 int waiting_time;
 int response_time;
} Process;

/* Function to calculate all scheduling metrics using FCFS */
void calculate_metrics(Process processes[], int n) {
 // Sort by arrival time (simple bubble sort for demonstration)
 for (int i = 0; i < n - 1; i++) {
 for (int j = 0; j < n - i - 1; j++) {
 if (processes[j].arrival_time > processes[j + 1].arrival_time) {
 Process temp = processes[j];
 processes[j] = processes[j + 1];
 processes[j + 1] = temp;
 }
 }
 }

 int current_time = 0;
 int total_idle_time = 0;
 int total_turnaround = 0;
 int total_waiting = 0;
 int total_response = 0;

 // Calculate metrics for each process
 for (int i = 0; i < n; i++) {
 // If CPU was idle before this process arrived
 if (current_time < processes[i].arrival_time) {
 total_idle_time += processes[i].arrival_time - current_time;
 current_time = processes[i].arrival_time;
 }

 // Response time: first time getting CPU
 if (current_time == processes[i].arrival_time) {
 processes[i].response_time = 0;
 } else {
 processes[i].response_time = current_time - processes[i].arrival_time;
 }

 // Execute the process
 current_time += processes[i].burst_time;
 processes[i].completion_time = current_time;

 // Turnaround time = Completion - Arrival
 processes[i].turnaround_time = processes[i].completion_time - processes[i].arrival_time;

 // Waiting time = Turnaround - Burst
 processes[i].waiting_time = processes[i].turnaround_time - processes[i].burst_time;

 // Accumulate totals
 total_turnaround += processes[i].turnaround_time;
 total_waiting += processes[i].waiting_time;
 total_response += processes[i].response_time;
 }

 // Calculate final scheduling criteria
 int total_time = current_time - processes[0].arrival_time;

 float cpu_utilization = ((float)(total_time - total_idle_time) / total_time) * 100.0f;
 float throughput = (float)n / total_time;
 float avg_turnaround = (float)total_turnaround / n;
 float avg_waiting = (float)total_waiting / n;
 float avg_response = (float)total_response / n;

 // Print per-process details
 printf("\n%-6s %-8s %-8s %-8s %-8s %-8s %-8s\n", 
 "PID", "Arrival", "Burst", "Complete", "TAT", "WT", "RT");
 printf("--------------------------------------------------------\n");
 for (int i = 0; i < n; i++) {
 printf("P%-5d %-8d %-8d %-8d %-8d %-8d %-8d\n",
 processes[i].pid,
 processes[i].arrival_time,
 processes[i].burst_time,
 processes[i].completion_time,
 processes[i].turnaround_time,
 processes[i].waiting_time,
 processes[i].response_time);
 }

 // Print scheduling criteria summary
 printf("\n========== SCHEDULING CRITERIA ==========\n");
 printf("CPU Utilization: %.2f%%\n", cpu_utilization);
 printf("Throughput: %.4f processes/time unit\n", throughput);
 printf("Avg Turnaround Time: %.2f time units\n", avg_turnaround);
 printf("Avg Waiting Time: %.2f time units\n", avg_waiting);
 printf("Avg Response Time: %.2f time units\n", avg_response);
 printf("==========================================\n");
}

int main() {
 int n = 5;

 // Sample processes: {PID, Arrival Time, Burst Time}
 Process processes[] = {
 {1, 0, 5},
 {2, 1, 3},
 {3, 2, 8},
 {4, 3, 4},
 {5, 4, 2}
 };

 printf("Scheduling Criteria Calculator\n");
 printf("FCFS Scheduling - 5 Processes\n");
 printf("Process Data:\n");
 printf(" P1: Arrival=0, Burst=5\n");
 printf(" P2: Arrival=1, Burst=3\n");
 printf(" P3: Arrival=2, Burst=8\n");
 printf(" P4: Arrival=3, Burst=4\n");
 printf(" P5: Arrival=4, Burst=2\n");

 calculate_metrics(processes, n);

 return 0;
}
